sql:
SELECT u.user_name, u.email, u.role, u.department, u.phone_number, u.notes, u.created_at, u.updated_at
FROM users u
JOIN studies s ON u.user_name = s.created_by;

SELECT experiment_type, COUNT(DISTINCT created_by) AS researchers
FROM studies
GROUP BY experiment_type;

SELECT isolate_id
FROM studies
WHERE experiment_type IN ('lab', 'greenhouse');

SELECT DISTINCT u.user_name, u.role, u.email, u.department
FROM users u
JOIN isolates i ON u.user_id = i.created_by AND u.user_id = i.updated_by;

SELECT *
FROM isolates
WHERE created_by = 'Alice Johnson' AND source = 'greenhouse population';

SELECT condition_name 
FROM conditions 
WHERE condition_id > 1;

SELECT studies.study_id, studies.created_by, conditions.condition_name
FROM studies
JOIN conditions ON studies.condition_id = conditions.condition_id;

external_knowledge:
- "dawn and dusk of the journey" refers to the start and end dates of the runs;
- "the final chapter" refers to the 'status' of the runs, here specifically 'completed';
- "growth phase of the pathogen" refers to the 'developmental_stage';
- "identifiers of the completed voyages" refer to 'run_id' and 'study_id';
- "weaving through the fabric of time, from the earliest to the latest" refers to ordering the results by 'start_date' in ascending order.

sql:
SELECT *
FROM studies
INNER JOIN runs ON studies.run_id = runs.run_id AND studies.study_id = runs.study_id;

external_knowledge:
- 'finished projects' refers to those runs or experiments with a status of 'completed';
- 'last year' in this context means the year 2023;
- The 'plant species involved' can be inferred from the `host_name` in the database, which provides the common name of the host plant species.

sql:
SELECT DISTINCT users.user_name
FROM users
JOIN studies ON users.user_name = studies.created_by OR users.user_name = studies.updated_by;

SELECT run_id, condition_id
FROM studies
ORDER BY condition_id ASC;
